import{_ as t,o as a,c as r,aQ as o}from"./chunks/framework.cDvftfeu.js";const c=JSON.parse('{"title":"開発者","description":"Ham開発者プロジェクトとドキュメントの概要。","frontmatter":{"description":"Ham開発者プロジェクトとドキュメントの概要。","next":{"text":"Ham Connect 概要","link":"/ja/developers/open-platform/"}},"headers":[],"relativePath":"ja/developers/index.md","filePath":"ja/developers/index.md","lastUpdated":1777525243000}'),n={name:"ja/developers/index.md"};function d(s,e,h,l,i,m){return a(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="開発者" tabindex="-1">開発者 <a class="header-anchor" href="#開発者" aria-label="Permalink to &quot;開発者&quot;">​</a></h1><p>Ham 開発者ドキュメントへようこそ！現在、以下のプロジェクトが含まれています：</p><table tabindex="0"><thead><tr><th>プロジェクト</th><th>説明</th><th>リポジトリ</th></tr></thead><tbody><tr><td><a href="/ja/developers/open-platform/">Ham Connect</a></td><td>オープンプラットフォーム OAuth 2.0 認証サービス</td><td>—</td></tr><tr><td><a href="/ja/developers/ham-web/">Ham Web</a></td><td>Web フロントエンド（SSO 認証など）</td><td><a href="https://github.com/whu-ham/ham-web" target="_blank" rel="noreferrer">GitHub</a></td></tr><tr><td><a href="/ja/developers/ham-rn/">Ham React Nativeコンポーネント</a></td><td>React Native コンポーネントリポジトリ、OTA ホットアップデートでネイティブアプリに統合</td><td><a href="https://github.com/whu-ham/ham-rn" target="_blank" rel="noreferrer">GitHub</a></td></tr></tbody></table><h2 id="概要" tabindex="-1">概要 <a class="header-anchor" href="#概要" aria-label="Permalink to &quot;概要&quot;">​</a></h2><p><strong>Ham Connect</strong> は Ham オープンプラットフォームが提供する OAuth 2.0 認証サービスで、サードパーティアプリが Ham ユーザーの認証情報を安全に取得し、「Ham でログイン」機能を実現できます。</p><p><strong>Ham Web</strong> は Ham の Web フロントエンドプロジェクトで、Next.js で構築されています。主に SSO シングルサインオン認証フロー（QR コードログイン、Passkey ログインを含む）を提供し、Ham Connect プラットフォームの Web エントリーポイントとして機能します。</p><p><strong>Ham React Nativeコンポーネント</strong> は Ham アプリの React Native コンポーネントリポジトリで、OTA ホットアップデートを通じてネイティブアプリに統合されています。教務システムの時間割照会、成績照会、GPA 計算、CAS 認証などのコア機能の UI とビジネスロジックを担当しています。</p><h2 id="コントリビューション" tabindex="-1">コントリビューション <a class="header-anchor" href="#コントリビューション" aria-label="Permalink to &quot;コントリビューション&quot;">​</a></h2><p>オープンソースプロジェクトは <a href="https://opensource.org/licenses/MIT" target="_blank" rel="noreferrer">MIT ライセンス</a> の下で公開されています。コミュニティからの貢献を歓迎します。PR を提出する前に、各プロジェクトのコントリビューションガイドをお読みください。</p>',9)])])}const b=t(n,[["render",d]]);export{c as __pageData,b as default};
